715: void UpstreamRequest::readDisableOrDefer(bool disable) {
716:   if (disable) {
717:     // See comments on deferred_read_disabling_count_ for when we do and don't defer.
718:     if (parent_.downstreamResponseStarted()) {
719:       // The downstream connection is overrun. Pause reads from upstream.
720:       // If there are multiple calls to readDisable either the codec (H2) or the
721:       // underlying Network::Connection (H1) will handle reference counting.
722:       parent_.cluster()->trafficStats()->upstream_flow_control_paused_reading_total_.inc();
723:       upstream_->readDisable(disable);
724:     } else {
725:       ++deferred_read_disabling_count_;
726:     }
727:     return;
728:   }
729: 
730:   // One source of connection blockage has buffer available.
731:   if (deferred_read_disabling_count_ > 0) {
732:     ASSERT(!parent_.downstreamResponseStarted());
733:     // Cancel out an existing deferred read disabling.
734:     --deferred_read_disabling_count_;
735:     return;
736:   }
737:   ASSERT(parent_.downstreamResponseStarted());
738:   // Pass this on to the stream, which
739:   // will resume reads if this was the last remaining high watermark.
740:   parent_.cluster()->trafficStats()->upstream_flow_control_resumed_reading_total_.inc();
741:   upstream_->readDisable(disable);
742: }
